#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int *dp = (int*)calloc(N+1, sizeof(int));
        for(int i=1;i<=N;i++) dp[i]=1;
        int C=1;
        for(int i=1;i<=N;i++){
            for(int j=i*2;j<=N;j+=i){
                if(dp[j] < dp[i]+1) dp[j] = dp[i]+1;
            }
            if(dp[i]>C) C=dp[i];
        }
        printf("%d\n", C);
        for(int i=1;i<=N;i++){
            if(i>1) printf(" ");
            printf("%d", dp[i]);
        }
        printf("\n");
        free(dp);
    }
    return 0;
}

