#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        dp = [1] * (N + 1)
        C = 1
        for i in range(1, N + 1):
            step = i
            j = i + step
            while j <= N:
                if dp[j] < dp[i] + 1:
                    dp[j] = dp[i] + 1
                j += step
            if dp[i] > C:
                C = dp[i]
        out_lines.append(str(C))
        out_lines.append(' '.join(str(dp[i]) for i in range(1, N + 1)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

